import hashlib

def chunk_with_metadata(text: str, source_url: str, page: int) -> dict:
    chunk_id = hashlib.sha256(text.encode()).hexdigest()[:12]
    return {
        "chunk_id": chunk_id,
        "text": text,
        "metadata": {
            "source_url": source_url,
            "page": page,
        },
    }

